Excellent question. A compromised update server can serve old vulnerable versions (rollback attack) or attackers can replay captured update packages. Production systems need multiple layers including version monotonicity, certificate pinning, and transparency logging.

**PRODUCTION PATTERN**:

```go
package updater

import (
	"context"
	"crypto/ed25519"
	"crypto/sha256"
	"crypto/tls"
	"crypto/x509"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"os"
	"strconv"
	"strings"
	"time"
)

// Configuration embedded at compile time
var (
	// Ed25519 public key for signature verification
	SigningPublicKey = mustDecodeHex("your_64_byte_ed25519_public_key_hex")

	// Certificate pins (SHA-256 of SPKI)
	CertificatePins = []string{
		"sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=",
		"sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=",
	}

	UpdateBaseURL   = "https://updates.example.com"
	CurrentVersion  = "2.1.0"
	MinimumVersion  = "2.0.0" // Prevents rollback below this
)

type UpdateManifest struct {
	Version       string    `json:"version"`
	VersionNumber int       `json:"version_number"` // Monotonic counter
	Checksum      string    `json:"checksum_sha256"`
	Signature     string    `json:"signature"`
	ReleaseDate   time.Time `json:"release_date"`
	MinOSVersion  string    `json:"min_os_version"`
	DownloadURL   string    `json:"download_url"`
	ReleaseNotes  string    `json:"release_notes"`
}

type SecureUpdater struct {
	httpClient       *http.Client
	logger           *slog.Logger
	publicKey        ed25519.PublicKey
	lastKnownVersion int
	stateFile        string
}

func mustDecodeHex(s string) []byte {
	b, err := hex.DecodeString(s)
	if err != nil {
		panic("invalid hex encoding: " + err.Error())
	}
	return b
}

func NewSecureUpdater(logger *slog.Logger, stateFile string) (*SecureUpdater, error) {
	// Create HTTP client with certificate pinning
	tlsConfig := &tls.Config{
		MinVersion: tls.VersionTLS13,
		VerifyPeerCertificate: createPinVerifier(CertificatePins),
	}

	client := &http.Client{
		Timeout: 30 * time.Second,
		Transport: &http.Transport{
			TLSClientConfig: tlsConfig,
		},
	}

	updater := &SecureUpdater{
		httpClient: client,
		logger:     logger,
		publicKey:  SigningPublicKey,
		stateFile:  stateFile,
	}

	// Load last known version to prevent rollback
	if err := updater.loadState(); err != nil {
		logger.Warn("Could not load update state", "error", err)
	}

	return updater, nil
}

func createPinVerifier(pins []string) func([][]byte, [][]*x509.Certificate) error {
	return func(rawCerts [][]byte, verifiedChains [][]*x509.Certificate) error {
		for _, chain := range verifiedChains {
			for _, cert := range chain {
				spkiHash := sha256.Sum256(cert.RawSubjectPublicKeyInfo)
				spkiPin := "sha256/" + hex.EncodeToString(spkiHash[:])

				for _, pin := range pins {
					if spkiPin == pin {
						return nil // Pin matched
					}
				}
			}
		}
		return fmt.Errorf("certificate pinning failed: no matching pin")
	}
}

func (u *SecureUpdater) loadState() error {
	data, err := os.ReadFile(u.stateFile)
	if err != nil {
		return err
	}
	u.lastKnownVersion, _ = strconv.Atoi(string(data))
	return nil
}

func (u *SecureUpdater) saveState(versionNumber int) error {
	return os.WriteFile(u.stateFile, []byte(strconv.Itoa(versionNumber)), 0600)
}

func (u *SecureUpdater) CheckForUpdate(ctx context.Context) (*UpdateManifest, error) {
	req, err := http.NewRequestWithContext(ctx, "GET", 
		UpdateBaseURL+"/manifest.json", nil)
	if err != nil {
		return nil, err
	}

	req.Header.Set("User-Agent", "SecureUpdater/1.0")
	req.Header.Set("X-Current-Version", CurrentVersion)

	resp, err := u.httpClient.Do(req)
	if err != nil {
		u.logger.Error("Failed to fetch manifest", "error", err)
		return nil, fmt.Errorf("manifest fetch failed: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("unexpected status: %d", resp.StatusCode)
	}

	// Read manifest with size limit
	limitedReader := io.LimitReader(resp.Body, 1*1024*1024) // 1MB max
	manifestData, err := io.ReadAll(limitedReader)
	if err != nil {
		return nil, err
	}

	var manifest UpdateManifest
	if err := json.Unmarshal(manifestData, &manifest); err != nil {
		return nil, fmt.Errorf("invalid manifest JSON: %w", err)
	}

	// Verify cryptographic signature over manifest
	if err := u.verifyManifestSignature(manifestData, manifest.Signature); err != nil {
		u.logger.Error("Manifest signature verification failed", 
			"error", err,
			"claimed_version", manifest.Version)
		return nil, fmt.Errorf("signature verification failed: %w", err)
	}

	// Rollback protection: version must be strictly increasing
	if manifest.VersionNumber <= u.lastKnownVersion {
		u.logger.Warn("Potential rollback attack detected",
			"manifest_version", manifest.VersionNumber,
			"last_known", u.lastKnownVersion)
		return nil, fmt.Errorf("rollback attack: version %d <= %d", 
			manifest.VersionNumber, u.lastKnownVersion)
	}

	// Verify version string format and minimum version
	if !u.isVersionNewer(manifest.Version, CurrentVersion) {
		return nil, nil // No update needed
	}

	if !u.isVersionNewer(manifest.Version, MinimumVersion) {
		u.logger.Warn("Update version below minimum",
			"update_version", manifest.Version,
			"minimum", MinimumVersion)
		return nil, fmt.Errorf("version below minimum allowed")
	}

	// Verify release date is not in the future (time-based attack prevention)
	if manifest.ReleaseDate.After(time.Now().Add(24 * time.Hour)) {
		return nil, fmt.Errorf("invalid release date: in the future")
	}

	u.logger.Info("Valid update available",
		"version", manifest.Version,
		"release_date", manifest.ReleaseDate)

	return &manifest, nil
}

func (u *SecureUpdater) verifyManifestSignature(manifestData []byte, signatureHex string) error {
	// Remove signature field from data before verification
	var rawManifest map[string]interface{}
	if err := json.Unmarshal(manifestData, &rawManifest); err != nil {
		return err
	}
	delete(rawManifest, "signature")

	canonicalData, err := json.Marshal(rawManifest)
	if err != nil {
		return err
	}

	signature, err := hex.DecodeString(signatureHex)
	if err != nil {
		return fmt.Errorf("invalid signature hex: %w", err)
	}

	if len(signature) != ed25519.SignatureSize {
		return fmt.Errorf("invalid signature length")
	}

	if !ed25519.Verify(u.publicKey, canonicalData, signature) {
		return fmt.Errorf("ed25519 signature invalid")
	}

	return nil
}

func (u *SecureUpdater) DownloadAndVerify(ctx context.Context, manifest *UpdateManifest) (string, error) {
	// Create secure temporary file
	tmpFile, err := os.CreateTemp("", "update-*.tmp")
	if err != nil {
		return "", err
	}
	tmpPath := tmpFile.Name()

	defer func() {
		tmpFile.Close()
		if err != nil {
			os.Remove(tmpPath)
		}
	}()

	// Download with context and size limit
	req, err := http.NewRequestWithContext(ctx, "GET", manifest.DownloadURL, nil)
	if err != nil {
		return "", err
	}

	resp, err := u.httpClient.Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()

	// Limit download size (100MB max)
	limitedReader := io.LimitReader(resp.Body, 100*1024*1024)

	// Stream to file while computing hash
	hasher := sha256.New()
	multiWriter := io.MultiWriter(tmpFile, hasher)

	if _, err := io.Copy(multiWriter, limitedReader); err != nil {
		return "", fmt.Errorf("download failed: %w", err)
	}

	// Verify checksum
	actualChecksum := hex.EncodeToString(hasher.Sum(nil))
	if actualChecksum != manifest.Checksum {
		u.logger.Error("Checksum mismatch",
			"expected", manifest.Checksum,
			"actual", actualChecksum)
		return "", fmt.Errorf("checksum verification failed")
	}

	// Save state to prevent rollback on next check
	if err := u.saveState(manifest.VersionNumber); err != nil {
		u.logger.Warn("Could not save update state", "error", err)
	}

	u.logger.Info("Update downloaded and verified",
		"version", manifest.Version,
		"checksum", actualChecksum,
		"path", tmpPath)

	return tmpPath, nil
}

func (u *SecureUpdater) isVersionNewer(new, current string) bool {
	newParts := strings.Split(new, ".")
	currentParts := strings.Split(current, ".")

	for i := 0; i < len(newParts) && i < len(currentParts); i++ {
		newNum, _ := strconv.Atoi(newParts[i])
		currNum, _ := strconv.Atoi(currentParts[i])
		if newNum > currNum {
			return true
		}
		if newNum < currNum {
			return false
		}
	}
	return len(newParts) > len(currentParts)
}
```

