const https = require('https');
const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

class SecureModuleLoader {
  constructor(config) {
    this.allowedModules = new Set(config.allowedModules || []);
    this.publicKey = fs.readFileSync(config.publicKeyPath, 'utf8');
    this.checksumRegistry = new Map(Object.entries(config.checksums || {}));
    this.localModulesPath = config.localModulesPath;
  }

  // SECURE: Verify cryptographic signature before loading
  verifySignature(code, signature) {
    const verify = crypto.createVerify('RSA-SHA256');
    verify.update(code);
    verify.end();
    return verify.verify(this.publicKey, signature, 'base64');
  }

  // SECURE: Verify content hash matches expected checksum
  verifyChecksum(moduleName, code) {
    const expectedChecksum = this.checksumRegistry.get(moduleName);
    if (!expectedChecksum) {
      throw new Error(`No checksum registered for module: ${moduleName}`);
    }
    const actualChecksum = crypto.createHash('sha256').update(code).digest('hex');
    return actualChecksum === expectedChecksum;
  }

  async loadModule(moduleName) {
    // SECURE: Allowlist of permitted modules
    if (!this.allowedModules.has(moduleName)) {
      throw new Error(`Module not in allowlist: ${moduleName}`);
    }

    // SECURE: Load from local verified path, not remote
    const modulePath = path.join(this.localModulesPath, `${moduleName}.js`);
    const signaturePath = path.join(this.localModulesPath, `${moduleName}.sig`);

    // Verify path traversal prevention
    const resolvedPath = path.resolve(modulePath);
    if (!resolvedPath.startsWith(path.resolve(this.localModulesPath))) {
      throw new Error('Path traversal detected');
    }

    const code = fs.readFileSync(modulePath, 'utf8');
    const signature = fs.readFileSync(signaturePath, 'utf8');

    // SECURE: Verify signature
    if (!this.verifySignature(code, signature)) {
      throw new Error(`Invalid signature for module: ${moduleName}`);
    }

    // SECURE: Verify checksum
    if (!this.verifyChecksum(moduleName, code)) {
      throw new Error(`Checksum mismatch for module: ${moduleName}`);
    }

    // SECURE: Use require() on verified local file
    return require(modulePath);
  }
}

