**PRODUCTION PATTERN**:

```javascript
const crypto = require('crypto');
const https = require('https');
const fs = require('fs');
const path = require('path');
const { pipeline } = require('stream/promises');
const EventEmitter = require('events');

class SecureUpdateManager extends EventEmitter {
  constructor(config) {
    super();
    this.currentVersion = config.currentVersion;
    this.updateServerUrl = config.updateServerUrl;
    this.stagingDir = config.stagingDir || './update-staging';
    this.backupDir = config.backupDir || './update-backup';

    // Multiple public keys for key rotation
    this.trustedPublicKeys = config.publicKeys.map(keyPath => 
      fs.readFileSync(keyPath, 'utf8')
    );

    // Certificate pinning for update server
    this.pinnedCertificates = config.pinnedCerts || [];

    // Audit logger
    this.auditLog = config.auditLogger || console;
  }

  // Verify signature with any trusted key (supports key rotation)
  verifySignature(data, signature) {
    for (const publicKey of this.trustedPublicKeys) {
      try {
        const verify = crypto.createVerify('RSA-SHA512');
        verify.update(data);
        verify.end();
        if (verify.verify(publicKey, signature, 'base64')) {
          return true;
        }
      } catch (e) {
        continue;
      }
    }
    return false;
  }

  // Secure HTTPS request with certificate pinning
  secureRequest(url) {
    return new Promise((resolve, reject) => {
      const options = {
        rejectUnauthorized: true,
        minVersion: 'TLSv1.3',
        checkServerIdentity: (host, cert) => {
          // Certificate pinning check
          const certFingerprint = crypto
            .createHash('sha256')
            .update(cert.raw)
            .digest('hex');

          if (this.pinnedCertificates.length > 0 && 
              !this.pinnedCertificates.includes(certFingerprint)) {
            return new Error('Certificate fingerprint mismatch - possible MITM attack');
          }
          return undefined;
        }
      };

      https.get(url, options, (response) => {
        if (response.statusCode !== 200) {
          reject(new Error(`Update server returned ${response.statusCode}`));
          return;
        }
        resolve(response);
      }).on('error', reject);
    });
  }

  async checkForUpdates() {
    this.auditLog.info('Checking for updates...');

    try {
      // Fetch signed manifest
      const manifestUrl = `${this.updateServerUrl}/manifest.json`;
      const sigUrl = `${this.updateServerUrl}/manifest.json.sig`;

      const manifestRes = await this.secureRequest(manifestUrl);
      const sigRes = await this.secureRequest(sigUrl);

      let manifestData = '';
      for await (const chunk of manifestRes) manifestData += chunk;

      let signature = '';
      for await (const chunk of sigRes) signature += chunk;

      // CRITICAL: Verify manifest signature before parsing
      if (!this.verifySignature(manifestData, signature.trim())) {
        this.auditLog.error('SECURITY ALERT: Update manifest signature invalid!');
        this.emit('security-alert', { type: 'invalid-signature', target: 'manifest' });
        throw new Error('Update manifest signature verification failed');
      }

      const manifest = JSON.parse(manifestData);

      // Validate manifest structure
      if (!manifest.version || !manifest.checksum || !manifest.downloadUrl) {
        throw new Error('Invalid manifest structure');
      }

      // Check if update is newer (prevent downgrade attacks)
      if (!this.isNewerVersion(manifest.version)) {
        this.auditLog.info(`Current version ${this.currentVersion} is up to date`);
        return null;
      }

      this.auditLog.info(`Update available: ${manifest.version}`);
      return manifest;

    } catch (error) {
      this.auditLog.error(`Update check failed: ${error.message}`);
      throw error;
    }
  }

  isNewerVersion(newVersion) {
    const current = this.currentVersion.split('.').map(Number);
    const update = newVersion.split('.').map(Number);

    for (let i = 0; i < Math.max(current.length, update.length); i++) {
      const c = current[i] || 0;
      const u = update[i] || 0;
      if (u > c) return true;
      if (u < c) return false;
    }
    return false;
  }

  async downloadAndVerifyUpdate(manifest) {
    this.auditLog.info(`Downloading update ${manifest.version}...`);

    // Create staging directory
    if (!fs.existsSync(this.stagingDir)) {
      fs.mkdirSync(this.stagingDir, { recursive: true });
    }

    const updatePath = path.join(this.stagingDir, `update-${manifest.version}.zip`);
    const signaturePath = path.join(this.stagingDir, `update-${manifest.version}.sig`);

    try {
      // Download update package
      const updateRes = await this.secureRequest(manifest.downloadUrl);
      const sigRes = await this.secureRequest(manifest.signatureUrl);

      // Stream to disk with hash computation
      const hash = crypto.createHash('sha512');
      const writeStream = fs.createWriteStream(updatePath);

      await pipeline(
        updateRes,
        async function* (source) {
          for await (const chunk of source) {
            hash.update(chunk);
            yield chunk;
          }
        },
        writeStream
      );

      // Verify checksum
      const actualChecksum = hash.digest('hex');
      if (actualChecksum !== manifest.checksum) {
        this.auditLog.error('SECURITY ALERT: Update checksum mismatch!');
        this.emit('security-alert', { type: 'checksum-mismatch', expected: manifest.checksum, actual: actualChecksum });
        fs.unlinkSync(updatePath);
        throw new Error('Update checksum verification failed');
      }

      // Download and verify signature
      let signature = '';
      for await (const chunk of sigRes) signature += chunk;
      fs.writeFileSync(signaturePath, signature);

      // Verify cryptographic signature
      const updateData = fs.readFileSync(updatePath);
      if (!this.verifySignature(updateData, signature.trim())) {
        this.auditLog.error('SECURITY ALERT: Update signature invalid!');
        this.emit('security-alert', { type: 'invalid-signature', target: 'update-package' });
        fs.unlinkSync(updatePath);
        fs.unlinkSync(signaturePath);
        throw new Error('Update signature verification failed');
      }

      this.auditLog.info(`Update ${manifest.version} downloaded and verified successfully`);

      return {
        updatePath,
        signaturePath,
        version: manifest.version,
        verified: true
      };

    } catch (error) {
      // Cleanup on failure
      if (fs.existsSync(updatePath)) fs.unlinkSync(updatePath);
      if (fs.existsSync(signaturePath)) fs.unlinkSync(signaturePath);
      throw error;
    }
  }

  async applyUpdate(verifiedUpdate) {
    if (!verifiedUpdate.verified) {
      throw new Error('Cannot apply unverified update');
    }

    this.auditLog.info(`Applying update ${verifiedUpdate.version}...`);

    // Create backup before applying
    const backupPath = path.join(this.backupDir, `backup-${this.currentVersion}-${Date.now()}`);
    fs.mkdirSync(backupPath, { recursive: true });

    try {
      // Backup current version
      await this.createBackup(backupPath);

      // Extract and apply update (implementation depends on your app structure)
      await this.extractUpdate(verifiedUpdate.updatePath);

      // Update version
      this.currentVersion = verifiedUpdate.version;

      this.auditLog.info(`Update ${verifiedUpdate.version} applied successfully`);
      this.emit('update-complete', { version: verifiedUpdate.version });

      return true;

    } catch (error) {
      this.auditLog.error(`Update failed, rolling back: ${error.message}`);
      await this.rollback(backupPath);
      throw error;
    }
  }

  async createBackup(backupPath) {
    // Implementation: copy current app files to backup
    this.auditLog.info(`Creating backup at ${backupPath}`);
  }

  async extractUpdate(updatePath) {
    // Implementation: extract verified update package
    this.auditLog.info(`Extracting update from ${updatePath}`);
  }

  async rollback(backupPath) {
    this.auditLog.warn(`Rolling back to backup at ${backupPath}`);
    // Implementation: restore from backup
  }
}

