import java.security.*;
import java.util.*;
import javax.net.ssl.*;

public class SecureCIBuildRunner {

    // Predefined trusted script hashes (SHA-256)
    private static final Map<String, String> TRUSTED_SCRIPT_HASHES = Map.of(
        "build.sh", "e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855",
        "deploy.sh", "a7ffc6f8bf1ed76651c14756a061d662f580ff4de43b49fa82d80a4b80f8434a"
    );

    // Allowlist of environment variables safe to expose
    private static final Set<String> SAFE_ENV_VARS = Set.of(
        "PATH", "HOME", "BUILD_NUMBER", "BRANCH_NAME", "WORKSPACE"
    );

    public void runBuildScript(String scriptName) throws Exception {
        // Only allow predefined script names
        if (!TRUSTED_SCRIPT_HASHES.containsKey(scriptName)) {
            throw new SecurityException("Unknown script: " + scriptName);
        }

        // Download from internal artifact repository only
        String scriptUrl = "https://internal-artifacts.company.com/scripts/" + scriptName;
        Path scriptPath = downloadWithVerification(scriptUrl, scriptName);

        // Execute with restricted environment
        executeWithRestrictedEnv(scriptPath);
    }

    private Path downloadWithVerification(String scriptUrl, String scriptName) 
            throws Exception {
        URL url = new URL(scriptUrl);
        HttpsURLConnection conn = (HttpsURLConnection) url.openConnection();

        // Verify TLS certificate
        conn.setSSLSocketFactory(getStrictSSLContext().getSocketFactory());

        byte[] scriptContent = conn.getInputStream().readAllBytes();

        // Verify SHA-256 hash before execution
        String actualHash = calculateSHA256(scriptContent);
        String expectedHash = TRUSTED_SCRIPT_HASHES.get(scriptName);

        if (!MessageDigest.isEqual(actualHash.getBytes(), expectedHash.getBytes())) {
            throw new SecurityException(
                "Script integrity check failed! Expected: " + expectedHash + 
                ", Got: " + actualHash);
        }

        System.out.println("[SECURITY] Script integrity verified: " + scriptName);

        Path scriptPath = Paths.get("/tmp/verified-" + scriptName);
        Files.write(scriptPath, scriptContent);
        scriptPath.toFile().setExecutable(true, true);

        return scriptPath;
    }

    private void executeWithRestrictedEnv(Path scriptPath) throws Exception {
        ProcessBuilder pb = new ProcessBuilder("bash", scriptPath.toString());

        // Clear all environment variables first
        pb.environment().clear();

        // Only expose safe, non-secret variables
        for (String safeVar : SAFE_ENV_VARS) {
            String value = System.getenv(safeVar);
            if (value != null) {
                pb.environment().put(safeVar, value);
            }
        }

        pb.redirectErrorStream(true);
        Process process = pb.start();

        // Log all output for audit
        try (BufferedReader reader = new BufferedReader(
                new InputStreamReader(process.getInputStream()))) {
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println("[BUILD] " + line);
            }
        }

        int exitCode = process.waitFor();
        if (exitCode != 0) {
            throw new RuntimeException("Build script failed with exit code: " + exitCode);
        }
    }

    private String calculateSHA256(byte[] data) throws NoSuchAlgorithmException {
        MessageDigest digest = MessageDigest.getInstance("SHA-256");
        byte[] hash = digest.digest(data);
        StringBuilder hexString = new StringBuilder();
        for (byte b : hash) {
            hexString.append(String.format("%02x", b));
        }
        return hexString.toString();
    }

    private SSLContext getStrictSSLContext() throws Exception {
        SSLContext sslContext = SSLContext.getInstance("TLS");
        sslContext.init(null, null, new SecureRandom());
        return sslContext;
    }
}
