import java.util.*;
import java.util.concurrent.*;
import java.util.logging.*;
import javax.crypto.*;
import javax.crypto.spec.*;
import javax.net.ssl.*;
import org.bouncycastle.openpgp.*;
import org.bouncycastle.openpgp.operator.jcajce.*;

public class SecureCIPipelineRunner {

    private static final Logger AUDIT_LOG = Logger.getLogger("CI_AUDIT");
    private static final Logger SECURITY_LOG = Logger.getLogger("CI_SECURITY");

    // SLSA Level 3 provenance tracking
    private final ProvenanceTracker provenanceTracker;
    private final SecretsManager secretsManager;
    private final SignatureVerifier signatureVerifier;
    private final ArtifactRegistry artifactRegistry;

    public SecureCIPipelineRunner() throws Exception {
        this.provenanceTracker = new ProvenanceTracker();
        this.secretsManager = new VaultSecretsManager();
        this.signatureVerifier = new GPGSignatureVerifier();
        this.artifactRegistry = new InternalArtifactRegistry();
    }

    public BuildResult executePipeline(PipelineConfig config) throws Exception {
        String buildId = UUID.randomUUID().toString();
        AUDIT_LOG.info(String.format("[BUILD:%s] Starting pipeline: %s", 
            buildId, config.getPipelineName()));

        try {
            // Step 1: Verify pipeline configuration signature
            verifyPipelineConfig(config, buildId);

            // Step 2: Download and verify all build scripts
            Map<String, Path> verifiedScripts = downloadAndVerifyScripts(
                config.getScripts(), buildId);

            // Step 3: Create isolated execution environment
            ExecutionEnvironment env = createIsolatedEnvironment(config, buildId);

            // Step 4: Inject secrets securely (just-in-time)
            injectSecretsSecurely(env, config.getRequiredSecrets(), buildId);

            // Step 5: Execute with full provenance tracking
            BuildResult result = executeWithProvenance(
                verifiedScripts, env, buildId);

            // Step 6: Sign and store artifacts
            signAndStoreArtifacts(result, buildId);

            AUDIT_LOG.info(String.format("[BUILD:%s] Pipeline completed successfully", 
                buildId));

            return result;

        } catch (SecurityException e) {
            SECURITY_LOG.severe(String.format(
                "[BUILD:%s] SECURITY VIOLATION: %s", buildId, e.getMessage()));
            alertSecurityTeam(buildId, e);
            throw e;
        } finally {
            // Always cleanup secrets from memory
            cleanupSecrets(buildId);
        }
    }

    private void verifyPipelineConfig(PipelineConfig config, String buildId) 
            throws Exception {
        AUDIT_LOG.info(String.format("[BUILD:%s] Verifying pipeline config signature", 
            buildId));

        // Verify the pipeline YAML/JSON is signed by authorized developer
        byte[] configBytes = config.getSerializedConfig();
        byte[] signature = config.getSignature();
        String signerId = config.getSignerId();

        // Check signer is in authorized list
        if (!isAuthorizedSigner(signerId)) {
            throw new SecurityException(
                "Pipeline signed by unauthorized user: " + signerId);
        }

        // Verify GPG signature
        if (!signatureVerifier.verifyDetachedSignature(
                configBytes, signature, signerId)) {
            throw new SecurityException(
                "Pipeline configuration signature verification failed");
        }

        AUDIT_LOG.info(String.format(
            "[BUILD:%s] Config signature verified, signer: %s", buildId, signerId));
    }

    private Map<String, Path> downloadAndVerifyScripts(
            List<ScriptReference> scripts, String buildId) throws Exception {

        Map<String, Path> verifiedScripts = new ConcurrentHashMap<>();

        for (ScriptReference script : scripts) {
            AUDIT_LOG.info(String.format("[BUILD:%s] Verifying script: %s@%s", 
                buildId, script.getName(), script.getVersion()));

            // Download from internal artifact registry only
            ArtifactMetadata metadata = artifactRegistry.getArtifact(
                script.getName(), script.getVersion());

            byte[] scriptContent = metadata.getContent();
            byte[] signature = metadata.getSignature();
            String expectedHash = metadata.getSha256Hash();

            // Verify SHA-256 hash
            String actualHash = calculateSHA256(scriptContent);
            if (!MessageDigest.isEqual(
                    actualHash.getBytes(), expectedHash.getBytes())) {
                throw new SecurityException(String.format(
                    "Script %s hash mismatch. Expected: %s, Got: %s",
                    script.getName(), expectedHash, actualHash));
            }

            // Verify GPG signature from build team key
            if (!signatureVerifier.verifyDetachedSignature(
                    scriptContent, signature, "build-team@company.com")) {
                throw new SecurityException(
                    "Script signature verification failed: " + script.getName());
            }

            // Write to secure temp location
            Path scriptPath = Files.createTempFile("verified-", "-" + script.getName());
            Files.write(scriptPath, scriptContent);
            scriptPath.toFile().setExecutable(true, true);

            // Record in provenance
            provenanceTracker.recordArtifact(buildId, script.getName(), 
                actualHash, metadata.getSignerId());

            verifiedScripts.put(script.getName(), scriptPath);

            AUDIT_LOG.info(String.format(
                "[BUILD:%s] Script %s verified (hash: %s, signer: %s)",
                buildId, script.getName(), actualHash.substring(0, 16), 
                metadata.getSignerId()));
        }

        return verifiedScripts;
    }

    private ExecutionEnvironment createIsolatedEnvironment(
            PipelineConfig config, String buildId) throws Exception {

        ExecutionEnvironment env = new ExecutionEnvironment();

        // Start with completely empty environment
        env.clearAllVariables();

        // Add only explicitly allowed variables
        Set<String> allowedVars = Set.of(
            "PATH", "HOME", "LANG", "BUILD_ID", "BRANCH_NAME", 
            "COMMIT_SHA", "WORKSPACE", "JAVA_HOME", "MAVEN_HOME"
        );

        for (String var : allowedVars) {
            String value = System.getenv(var);
            if (value != null) {
                env.setVariable(var, value);
            }
        }

        // Add build-specific variables
        env.setVariable("BUILD_ID", buildId);
        env.setVariable("WORKSPACE", "/tmp/build-" + buildId);

        // Create isolated workspace
        Path workspace = Paths.get(env.getVariable("WORKSPACE"));
        Files.createDirectories(workspace);

        AUDIT_LOG.info(String.format(
            "[BUILD:%s] Created isolated environment with %d variables",
            buildId, env.getVariableCount()));

        return env;
    }

    private void injectSecretsSecurely(
            ExecutionEnvironment env, 
            List<SecretReference> requiredSecrets,
            String buildId) throws Exception {

        for (SecretReference secretRef : requiredSecrets) {
            // Verify this secret is allowed for this pipeline
            if (!secretsManager.isSecretAllowed(
                    secretRef.getSecretPath(), env.getVariable("BRANCH_NAME"))) {
                throw new SecurityException(String.format(
                    "Secret %s not allowed for branch %s",
                    secretRef.getSecretPath(), env.getVariable("BRANCH_NAME")));
            }

            // Fetch secret just-in-time from Vault
            SecretValue secret = secretsManager.getSecret(
                secretRef.getSecretPath(), buildId);

            // Inject as environment variable (will be cleared after build)
            env.setSecretVariable(secretRef.getEnvName(), secret.getValue());

            // Record secret access (not the value!)
            AUDIT_LOG.info(String.format(
                "[BUILD:%s] Secret injected: %s -> %s",
                buildId, secretRef.getSecretPath(), secretRef.getEnvName()));
        }
    }

    private BuildResult executeWithProvenance(
            Map<String, Path> scripts,
            ExecutionEnvironment env,
            String buildId) throws Exception {

        BuildResult result = new BuildResult(buildId);

        for (Map.Entry<String, Path> entry : scripts.entrySet()) {
            String scriptName = entry.getKey();
            Path scriptPath = entry.getValue();

            long startTime = System.currentTimeMillis();

            ProcessBuilder pb = new ProcessBuilder("bash", scriptPath.toString());
            pb.directory(new File(env.getVariable("WORKSPACE")));
            pb.environment().clear();
            pb.environment().putAll(env.getAllVariables());
            pb.redirectErrorStream(true);

            Process process = pb.start();

            // Capture all output for audit
            StringBuilder output = new StringBuilder();
            try (BufferedReader reader = new BufferedReader(
                    new InputStreamReader(process.getInputStream()))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    output.append(line).append("\n");
                    // Redact potential secrets from logs
                    String redactedLine = redactSecrets(line, env);
                    System.out.println("[BUILD:" + buildId + "] " + redactedLine);
                }
            }

            int exitCode = process.waitFor();
            long duration = System.currentTimeMillis() - startTime;

            // Record provenance
            provenanceTracker.recordExecution(buildId, scriptName, 
                exitCode, duration, calculateSHA256(output.toString().getBytes()));

            if (exitCode != 0) {
                throw new BuildException(String.format(
                    "Script %s failed with exit code %d", scriptName, exitCode));
            }

            result.addScriptResult(scriptName, exitCode, duration);
        }

        return result;
    }

    private void signAndStoreArtifacts(BuildResult result, String buildId) 
            throws Exception {

        Path workspace = Paths.get("/tmp/build-" + buildId);

        // Find all output artifacts
        List<Path> artifacts = Files.walk(workspace)
            .filter(p -> p.toString().endsWith(".jar") || 
                        p.toString().endsWith(".war") ||
                        p.toString().endsWith(".zip"))
            .toList();

        for (Path artifact : artifacts) {
            byte[] content = Files.readAllBytes(artifact);
            String hash = calculateSHA256(content);

            // Sign artifact with build service key
            byte[] signature = signatureVerifier.signArtifact(
                content, "ci-service@company.com");

            // Generate SLSA provenance attestation
            String provenance = provenanceTracker.generateSLSAProvenance(
                buildId, artifact.getFileName().toString(), hash);

            // Store in artifact registry
            artifactRegistry.storeArtifact(
                artifact.getFileName().toString(),
                content,
                signature,
                hash,
                provenance
            );

            AUDIT_LOG.info(String.format(
                "[BUILD:%s] Artifact signed and stored: %s (hash: %s)",
                buildId, artifact.getFileName(), hash.substring(0, 16)));
        }
    }

    private void cleanupSecrets(String buildId) {
        try {
            // Explicitly zero out secret memory
            secretsManager.revokeSessionSecrets(buildId);

            // Delete workspace
            Path workspace = Paths.get("/tmp/build-" + buildId);
            if (Files.exists(workspace)) {
                Files.walk(workspace)
                    .sorted(Comparator.reverseOrder())
                    .forEach(path -> {
                        try { Files.delete(path); } 
                        catch (IOException ignored) {}
                    });
            }

            AUDIT_LOG.info(String.format(
                "[BUILD:%s] Secrets and workspace cleaned up", buildId));
        } catch (Exception e) {
            SECURITY_LOG.warning(String.format(
                "[BUILD:%s] Cleanup error: %s", buildId, e.getMessage()));
        }
    }

    private String redactSecrets(String line, ExecutionEnvironment env) {
        String redacted = line;
        for (String secretVar : env.getSecretVariableNames()) {
            String secretValue = env.getVariable(secretVar);
            if (secretValue != null && redacted.contains(secretValue)) {
                redacted = redacted.replace(secretValue, "[REDACTED:" + secretVar + "]");
            }
        }
        return redacted;
    }

    private String calculateSHA256(byte[] data) throws NoSuchAlgorithmException {
        MessageDigest digest = MessageDigest.getInstance("SHA-256");
        byte[] hash = digest.digest(data);
        StringBuilder hexString = new StringBuilder();
        for (byte b : hash) {
            hexString.append(String.format("%02x", b));
        }
        return hexString.toString();
    }

    private boolean isAuthorizedSigner(String signerId) {
        // Check against allowlist in secure configuration
        Set<String> authorizedSigners = Set.of(
            "lead-dev@company.com",
            "senior-dev@company.com",
            "ci-service@company.com"
        );
        return authorizedSigners.contains(signerId);
    }

