public class GPGSignatureVerifier {
    private final Map<String, PGPPublicKey> trustedKeys;

    public boolean verifyDetachedSignature(
            byte[] data, byte[] signature, String expectedSignerId) 
            throws Exception {

        PGPPublicKey publicKey = trustedKeys.get(expectedSignerId);
        if (publicKey == null) {
            throw new SecurityException("Unknown signer: " + expectedSignerId);
        }

        // Verify using BouncyCastle
        PGPSignature sig = new PGPSignature(
            new ByteArrayInputStream(signature));
        sig.init(new JcaPGPContentVerifierBuilderProvider(), publicKey);
        sig.update(data);

        return sig.verify();
    }
}
