// Embedded public key for signature verification
var trustedPublicKey = mustDecodePublicKey(os.Getenv("CONFIG_PUBLIC_KEY"))

type SecureConfig struct {
	DatabaseURL string   `json:"database_url"`
	APIKey      string   `json:"api_key"`
	AllowedHosts []string `json:"allowed_hosts"`
}

type SignedPayload struct {
	Config    json.RawMessage `json:"config"`
	Signature string          `json:"signature"`
	Checksum  string          `json:"checksum"`
}

func mustDecodePublicKey(b64Key string) ed25519.PublicKey {
	key, err := base64.StdEncoding.DecodeString(b64Key)
	if err != nil || len(key) != ed25519.PublicKeySize {
		panic("invalid public key")
	}
	return ed25519.PublicKey(key)
}

func verifyAndLoadConfig(url string) (*SecureConfig, error) {
	// Only allow HTTPS
	if !strings.HasPrefix(url, "https://") {
		return nil, errors.New("config URL must use HTTPS")
	}

	resp, err := http.Get(url)
	if err != nil {
		return nil, fmt.Errorf("failed to fetch config: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("unexpected status: %d", resp.StatusCode)
	}

	data, err := io.ReadAll(io.LimitReader(resp.Body, 1<<20)) // 1MB limit
	if err != nil {
		return nil, fmt.Errorf("failed to read config: %w", err)
	}

	var payload SignedPayload
	if err := json.Unmarshal(data, &payload); err != nil {
		return nil, fmt.Errorf("invalid payload format: %w", err)
	}

	// INTEGRITY CHECK 1: Verify SHA-256 checksum
	computedHash := sha256.Sum256(payload.Config)
	expectedHash, err := hex.DecodeString(payload.Checksum)
	if err != nil || !equalBytes(computedHash[:], expectedHash) {
		return nil, errors.New("checksum verification failed")
	}

	// INTEGRITY CHECK 2: Verify Ed25519 signature
	signature, err := base64.StdEncoding.DecodeString(payload.Signature)
	if err != nil {
		return nil, errors.New("invalid signature encoding")
	}

	if !ed25519.Verify(trustedPublicKey, payload.Config, signature) {
		return nil, errors.New("signature verification failed")
	}

	// Parse config only after integrity verification
	var config SecureConfig
	if err := json.Unmarshal(payload.Config, &config); err != nil {
		return nil, fmt.Errorf("invalid config format: %w", err)
	}

	return &config, nil
}

func equalBytes(a, b []byte) bool {
	if len(a) != len(b) {
		return false
	}
	var result byte
	for i := range a {
		result |= a[i] ^ b[i]
	}
	return result == 0
}

func main() {
	config, err := verifyAndLoadConfig(os.Getenv("CONFIG_URL"))
	if err != nil {
		fmt.Println("Config verification failed:", err)
		os.Exit(1)
	}
	fmt.Printf("Verified config loaded: %+v\n", config)
}
```

**Key Security Controls**:
- **Cryptographic signature verification**: Ed25519 digital signature ensures config was created by trusted source with the private key
- **Checksum validation**: SHA-256 hash detects any modification to the configuration content
- **Constant-time comparison**: Prevents timing attacks on hash/signature comparison
- **No dangerous fields**: Removed startup_cmd and plugin_urls that could execute arbitrary code
- **HTTPS enforcement**: Ensures transport-layer encryption
- **Size limiting**: Prevents denial of service via oversized payloads

Verifying downloaded binaries is critical for preventing supply chain attacks. You need a multi-layered approach with cryptographic verification, trusted sources, and runtime monitoring.

**PRODUCTION PATTERN**:

```go
package integrity

import (
	"context"
	"crypto/ed25519"
	"crypto/sha256"
	"crypto/sha512"
	"encoding/base64"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"os"
	"path/filepath"
	"strings"
	"sync"
	"time"
)

var (
	ErrIntegrityCheckFailed  = errors.New("integrity check failed")
	ErrUntrustedSource       = errors.New("untrusted source")
	ErrSignatureInvalid      = errors.New("signature verification failed")
	ErrCertificateRevoked    = errors.New("signing certificate revoked")
)

// TrustStore manages trusted signing keys and revocations
type TrustStore struct {
	mu             sync.RWMutex
	trustedKeys    map[string]ed25519.PublicKey // keyID -> public key
	revokedKeys    map[string]time.Time         // keyID -> revocation time
	allowedSources []string                     // Allowed download domains
	logger         *slog.Logger
}

// Manifest describes a downloadable artifact with integrity info
type Manifest struct {
	Name        string `json:"name"`
	Version     string `json:"version"`
	URL         string `json:"url"`
	SHA256      string `json:"sha256"`
	SHA512      string `json:"sha512"`
	Size        int64  `json:"size"`
	KeyID       string `json:"key_id"`
	Signature   string `json:"signature"`
	SignedAt    int64  `json:"signed_at"`
	MinVersion  string `json:"min_version,omitempty"` // Prevents downgrade attacks
}

// IntegrityVerifier handles secure artifact downloads
type IntegrityVerifier struct {
	trustStore     *TrustStore
	httpClient     *http.Client
	downloadDir    string
	logger         *slog.Logger
	auditLog       *AuditLogger
	maxFileSize    int64
	allowedFormats []string
}

type AuditLogger struct {
	logger *slog.Logger
}

func (a *AuditLogger) LogDownload(ctx context.Context, manifest *Manifest, success bool, reason string) {
	a.logger.InfoContext(ctx, "artifact_download",
		"artifact_name", manifest.Name,
		"artifact_version", manifest.Version,
		"artifact_url", manifest.URL,
		"sha256", manifest.SHA256,
		"key_id", manifest.KeyID,
		"success", success,
		"reason", reason,
		"timestamp", time.Now().UTC().Format(time.RFC3339),
	)
}

func NewIntegrityVerifier(trustStore *TrustStore, downloadDir string, logger *slog.Logger) *IntegrityVerifier {
	return &IntegrityVerifier{
		trustStore:  trustStore,
		downloadDir: downloadDir,
		logger:      logger,
		auditLog:    &AuditLogger{logger: logger},
		httpClient: &http.Client{
			Timeout: 5 * time.Minute,
			Transport: &http.Transport{
				MaxIdleConns:        10,
				IdleConnTimeout:     30 * time.Second,
				DisableCompression:  true, // Prevent zip bombs
				ForceAttemptHTTP2:   true,
			},
		},
		maxFileSize:    100 * 1024 * 1024, // 100MB default
		allowedFormats: []string{".so", ".dll", ".dylib", ".wasm"},
	}
}

func (iv *IntegrityVerifier) VerifyAndDownload(ctx context.Context, manifest *Manifest) (string, error) {
	// LAYER 1: Validate manifest signature
	if err := iv.verifyManifestSignature(manifest); err != nil {
		iv.auditLog.LogDownload(ctx, manifest, false, err.Error())
		return "", fmt.Errorf("%w: %v", ErrSignatureInvalid, err)
	}

	// LAYER 2: Verify source is trusted
	if err := iv.validateSource(manifest.URL); err != nil {
		iv.auditLog.LogDownload(ctx, manifest, false, err.Error())
		return "", fmt.Errorf("%w: %v", ErrUntrustedSource, err)
	}

	// LAYER 3: Check signing key is not revoked
	if err := iv.trustStore.CheckKeyNotRevoked(manifest.KeyID, time.Unix(manifest.SignedAt, 0)); err != nil {
		iv.auditLog.LogDownload(ctx, manifest, false, err.Error())
		return "", err
	}

	// LAYER 4: Download to temporary location
	tempPath, err := iv.downloadToTemp(ctx, manifest)
	if err != nil {
		iv.auditLog.LogDownload(ctx, manifest, false, err.Error())
		return "", err
	}

	// LAYER 5: Verify file hashes (both SHA-256 and SHA-512)
	if err := iv.verifyFileHashes(tempPath, manifest); err != nil {
		os.Remove(tempPath) // Clean up failed download
		iv.auditLog.LogDownload(ctx, manifest, false, err.Error())
		return "", fmt.Errorf("%w: %v", ErrIntegrityCheckFailed, err)
	}

	// LAYER 6: Move to final location with restricted permissions
	finalPath := filepath.Join(iv.downloadDir, filepath.Base(manifest.Name))
	if err := iv.secureMoveFile(tempPath, finalPath); err != nil {
		os.Remove(tempPath)
		iv.auditLog.LogDownload(ctx, manifest, false, err.Error())
		return "", err
	}

	iv.auditLog.LogDownload(ctx, manifest, true, "integrity verified")
	iv.logger.InfoContext(ctx, "artifact downloaded and verified",
		"path", finalPath,
		"sha256", manifest.SHA256,
	)

	return finalPath, nil
}

func (iv *IntegrityVerifier) verifyManifestSignature(manifest *Manifest) error {
	// Reconstruct the signed message
	signedData := fmt.Sprintf("%s|%s|%s|%s|%s|%d|%d",
		manifest.Name,
		manifest.Version,
		manifest.URL,
		manifest.SHA256,
		manifest.SHA512,
		manifest.Size,
		manifest.SignedAt,
	)

	// Get the public key for this key ID
	publicKey, err := iv.trustStore.GetKey(manifest.KeyID)
	if err != nil {
		return fmt.Errorf("unknown signing key: %s", manifest.KeyID)
	}

	// Decode and verify signature
	signature, err := base64.StdEncoding.DecodeString(manifest.Signature)
	if err != nil {
		return errors.New("invalid signature encoding")
	}

	if !ed25519.Verify(publicKey, []byte(signedData), signature) {
		return errors.New("signature does not match")
	}

	// Check signature freshness (prevent replay attacks)
	signedTime := time.Unix(manifest.SignedAt, 0)
	if time.Since(signedTime) > 7*24*time.Hour {
		return errors.New("signature too old, possible replay attack")
	}

	return nil
}

func (iv *IntegrityVerifier) validateSource(url string) error {
	// Enforce HTTPS
	if !strings.HasPrefix(url, "https://") {
		return errors.New("URL must use HTTPS")
	}

	// Check against allowlist
	for _, allowed := range iv.trustStore.allowedSources {
		if strings.Contains(url, allowed) {
			return nil
		}
	}

	return fmt.Errorf("source not in allowlist: %s", url)
}

func (iv *IntegrityVerifier) downloadToTemp(ctx context.Context, manifest *Manifest) (string, error) {
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, manifest.URL, nil)
	if err != nil {
		return "", err
	}

	resp, err := iv.httpClient.Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return "", fmt.Errorf("download failed with status: %d", resp.StatusCode)
	}

	// Validate Content-Length matches expected size
	if resp.ContentLength > 0 && resp.ContentLength != manifest.Size {
		return "", fmt.Errorf("size mismatch: expected %d, got %d", manifest.Size, resp.ContentLength)
	}

	// Create temp file with restricted permissions
	tempFile, err := os.CreateTemp(iv.downloadDir, "artifact-*.tmp")
	if err != nil {
		return "", err
	}
	defer tempFile.Close()

	if err := os.Chmod(tempFile.Name(), 0600); err != nil {
		os.Remove(tempFile.Name())
		return "", err
	}

	// Limit download size to prevent resource exhaustion
	limitedReader := io.LimitReader(resp.Body, iv.maxFileSize)

	written, err := io.Copy(tempFile, limitedReader)
	if err != nil {
		os.Remove(tempFile.Name())
		return "", err
	}

	if written != manifest.Size {
		os.Remove(tempFile.Name())
		return "", fmt.Errorf("downloaded size mismatch: expected %d, got %d", manifest.Size, written)
	}

	return tempFile.Name(), nil
}

func (iv *IntegrityVerifier) verifyFileHashes(filePath string, manifest *Manifest) error {
	file, err := os.Open(filePath)
	if err != nil {
		return err
	}
	defer file.Close()

	// Compute both hashes in a single pass
	sha256Hash := sha256.New()
	sha512Hash := sha512.New()
	multiWriter := io.MultiWriter(sha256Hash, sha512Hash)

	if _, err := io.Copy(multiWriter, file); err != nil {
		return err
	}

	// Verify SHA-256
	computedSHA256 := hex.EncodeToString(sha256Hash.Sum(nil))
	if !constantTimeCompare(computedSHA256, strings.ToLower(manifest.SHA256)) {
		return fmt.Errorf("SHA-256 mismatch: expected %s, got %s", manifest.SHA256, computedSHA256)
	}

	// Verify SHA-512
	computedSHA512 := hex.EncodeToString(sha512Hash.Sum(nil))
	if !constantTimeCompare(computedSHA512, strings.ToLower(manifest.SHA512)) {
		return fmt.Errorf("SHA-512 mismatch: expected %s, got %s", manifest.SHA512, computedSHA512)
	}

	return nil
}

func constantTimeCompare(a, b string) bool {
	if len(a) != len(b) {
		return false
	}
	var result byte
	for i := 0; i < len(a); i++ {
		result |= a[i] ^ b[i]
	}
	return result == 0
}

func (iv *IntegrityVerifier) secureMoveFile(src, dst string) error {
	// Ensure destination directory exists with correct permissions
	dstDir := filepath.Dir(dst)
	if err := os.MkdirAll(dstDir, 0750); err != nil {
		return err
	}

	// Atomic rename if on same filesystem, otherwise copy+delete
	if err := os.Rename(src, dst); err != nil {
		// Fallback to copy if rename fails (cross-device)
		if err := copyFile(src, dst); err != nil {
			return err
		}
		os.Remove(src)
	}

	// Set restrictive permissions on final file
	return os.Chmod(dst, 0640)
}

func copyFile(src, dst string) error {
	srcFile, err := os.Open(src)
	if err != nil {
		return err
	}
	defer srcFile.Close()

	dstFile, err := os.OpenFile(dst, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0600)
	if err != nil {
		return err
	}
	defer dstFile.Close()

	_, err = io.Copy(dstFile, srcFile)
	return err
}

func (ts *TrustStore) GetKey(keyID string) (ed25519.PublicKey, error) {
	ts.mu.RLock()
	defer ts.mu.RUnlock()

	key, exists := ts.trustedKeys[keyID]
	if !exists {
		return nil, fmt.Errorf("key not found: %s", keyID)
	}
	return key, nil
}

func (ts *TrustStore) CheckKeyNotRevoked(keyID string, signedAt time.Time) error {
	ts.mu.RLock()
	defer ts.mu.RUnlock()

	revocationTime, revoked := ts.revokedKeys[keyID]
	if revoked && signedAt.After(revocationTime) {
		return fmt.Errorf("%w: key %s was revoked at %v", ErrCertificateRevoked, keyID, revocationTime)
	}
	return nil
}
```

**Defense in Depth Layers**:

1. **Manifest Signature Verification**: Every download manifest must be signed with Ed25519 by a trusted key. The signature covers all critical fields including name, version, hashes, and timestamp to prevent tampering.

2. **Dual Hash Verification**: Both SHA-256 and SHA-512 checksums are verified. This protects against theoretical hash collision attacks and ensures maximum integrity assurance.

3. **Source Allowlisting**: Downloads are only permitted from pre-approved domains, preventing attackers from redirecting to malicious sources even if they compromise the manifest.

4. **Key Revocation Checking**: The trust store maintains a revocation list. If a signing key is compromised, all artifacts signed after the revocation date are rejected.

5. **Signature Freshness**: Manifests older than 7 days are rejected to prevent replay attacks where an attacker serves an old, vulnerable version.

6. **Size Validation**: File sizes are checked both from Content-Length header and after download to detect truncation or padding attacks.

**Additional Protections**:

- **Constant-time comparison**: All cryptographic comparisons use constant-time operations to prevent timing attacks
- **Audit logging**: Every download attempt is logged with full context for incident response
- **Restrictive file permissions**: Downloaded artifacts have 0640 permissions, readable only by owner and group
- **Resource limits**: Maximum file size limits prevent denial of service via oversized downloads
- **Atomic operations**: File moves use atomic rename when possible to prevent partial file issues
- **HTTP/2 with disabled compression**: Prevents CRIME/BREACH style attacks and zip bombs
- **Context-aware cancellation**: Downloads respect context cancellation for proper timeout handling

