const https = require('https');
const fs = require('fs');
const crypto = require('crypto');
const path = require('path');
const { spawn } = require('child_process');

class SecureAutoUpdater {
  constructor(config) {
    this.updateUrl = config.updateUrl;
    this.downloadPath = path.join(__dirname, 'update.exe');
    // Embed the public key for signature verification
    this.publicKey = config.publicKey;
    this.allowedHosts = config.allowedHosts;
  }

  verifySignature(data, signature) {
    const verify = crypto.createVerify('RSA-SHA256');
    verify.update(data);
    verify.end();
    return verify.verify(this.publicKey, signature, 'base64');
  }

  verifyChecksum(filePath, expectedHash) {
    return new Promise((resolve, reject) => {
      const hash = crypto.createHash('sha256');
      const stream = fs.createReadStream(filePath);
      stream.on('data', chunk => hash.update(chunk));
      stream.on('end', () => {
        const calculatedHash = hash.digest('hex');
        resolve(calculatedHash === expectedHash);
      });
      stream.on('error', reject);
    });
  }

  isAllowedHost(url) {
    try {
      const parsedUrl = new URL(url);
      return this.allowedHosts.includes(parsedUrl.hostname);
    } catch {
      return false;
    }
