      }).on('error', reject);
    });
  }

  async downloadUpdate(manifest) {
    // Verify download URL is from allowed host
    if (!this.isAllowedHost(manifest.downloadUrl)) {
      throw new Error('Download URL not from allowed host');
    }

    return new Promise((resolve, reject) => {
      const file = fs.createWriteStream(this.downloadPath);
      https.get(manifest.downloadUrl, (res) => {
        res.pipe(file);
        file.on('finish', async () => {
          file.close();
          // Verify downloaded file checksum
          const checksumValid = await this.verifyChecksum(
            this.downloadPath,
            manifest.sha256
          );
          if (!checksumValid) {
            fs.unlinkSync(this.downloadPath);
            reject(new Error('Downloaded file checksum mismatch'));
            return;
          }
          resolve(this.downloadPath);
        });
      }).on('error', reject);
    });
  }

  async installUpdate() {
    // Spawn with limited privileges, don't inherit shell
    return new Promise((resolve, reject) => {
      const child = spawn(this.downloadPath, [], {
        detached: true,
        stdio: 'ignore'
      });
      child.unref();
      resolve();
    });
  }
}
```

**Key Security Controls**:
- **Cryptographic signature verification**: Updates must be signed with a private key; public key embedded in app
- **SHA-256 checksum verification**: Downloaded files are hashed and compared against signed manifest
- **Certificate pinning**: Prevents MITM attacks even with compromised CAs
- **Host allowlisting**: Only downloads from pre-approved domains

